import { Field as FieldPrimitive } from '@ark-ui/react/field';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { ChevronDownIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './NativeSelect.module.css';

type NativeSelectRootProps = ComponentProps<typeof FieldPrimitive.Select> & {
  controlProps?: ComponentProps<'span'>;
};

const NativeSelectRoot = forwardRef<
  ComponentRef<typeof FieldPrimitive.Select>,
  NativeSelectRootProps
>(function NativeSelectRoot({ className, controlProps, ...props }, ref) {
  return (
    <span
      {...controlProps}
      data-scope="native-select"
      data-part="control"
      data-slot="native-select-control"
      className={clsx(styles.control, normalizeClassName(controlProps?.className))}
    >
      <FieldPrimitive.Select
        {...props}
        ref={ref}
        data-slot="native-select-root"
        className={clsx(styles.root, normalizeClassName(className))}
      />
      <span
        aria-hidden="true"
        data-scope="native-select"
        data-part="indicator"
        data-slot="native-select-indicator"
        className={styles.indicator}
      >
        <ChevronDownIcon />
      </span>
    </span>
  );
});

const NativeSelect = Object.assign(NativeSelectRoot, {
  Root: NativeSelectRoot,
});

export { NativeSelect };

@layer ui.components {
  .control {
    position: relative;
    display: inline-grid;
    width: fit-content;
    max-width: 100%;
    min-width: 0;
  }

  .root {
    box-sizing: border-box;
    width: var(--select-width, 14rem);
    max-width: var(--select-max-width, 100%);
    min-width: 0;
    height: var(--select-control-height, var(--size-md));
    margin: 0;
    border: var(--select-border-width, var(--border-width-sm)) solid
      var(--select-border-color, var(--color-border));
    border-radius: var(--select-radius, var(--radius-md));
    padding-inline-start: var(--select-trigger-padding-x-start, var(--spacing-3));
    padding-inline-end: calc(
      var(--select-action-offset-right, var(--spacing-1)) +
        var(--select-action-size, var(--spacing-6)) +
        var(--select-trigger-padding-x-start, var(--spacing-3))
    );
    appearance: none;
    background-color: var(--select-bg, var(--color-background));
    color: var(--select-color, var(--color-foreground));
    font: inherit;
    outline: var(--select-focus-ring-width, var(--focus-ring-inset-width, var(--border-width-sm)))
      solid transparent;
    outline-offset: calc(
      var(--select-focus-ring-width, var(--focus-ring-inset-width, var(--border-width-sm))) * -1
    );
    cursor: pointer;
    transition:
      background-color var(--select-transition, var(--transition-default)),
      border-color var(--select-transition, var(--transition-default)),
      outline-color var(--select-transition, var(--transition-default)),
      opacity var(--select-transition, var(--transition-default));

    &:focus-visible {
      border-color: var(--select-focus-ring-color, var(--color-ring));
      outline-color: var(--select-focus-ring-color, var(--color-ring));
    }

    &:is([data-invalid], [aria-invalid='true']) {
      border-color: var(--select-invalid-color, var(--color-destructive));
      outline-color: var(--select-invalid-color, var(--color-destructive));
    }

    &:is([data-disabled], :disabled) {
      pointer-events: none;
      opacity: var(--select-disabled-opacity, var(--opacity-disabled));
    }

    &:is([multiple], [size]:not([size='1'])) {
      height: auto;
      padding-block: var(--spacing-2);
      padding-inline: var(--select-trigger-padding-x-start, var(--spacing-3));
      appearance: auto;
    }

    @media (forced-colors: active) {
      padding-inline-end: var(--select-trigger-padding-x-start, var(--spacing-3));
      appearance: auto;
    }
  }

  .indicator {
    position: absolute;
    top: 50%;
    inset-inline-end: var(--select-action-offset-right, var(--spacing-2));
    display: inline-flex;
    width: var(--select-action-size, var(--spacing-6));
    height: var(--select-action-size, var(--spacing-6));
    align-items: center;
    justify-content: center;
    border-radius: var(--select-action-radius, var(--radius-sm));
    background: var(--select-action-bg, transparent);
    color: var(--select-icon-color, var(--color-muted-foreground));
    line-height: 0;
    pointer-events: none;
    transform: translateY(-50%);
    transition:
      background-color var(--select-transition, var(--transition-default)),
      color var(--select-transition, var(--transition-default)),
      opacity var(--select-transition, var(--transition-default));

    & > svg {
      display: block;
      width: var(--select-icon-size, var(--spacing-4));
      height: var(--select-icon-size, var(--spacing-4));
    }

    @media (forced-colors: active) {
      display: none;
    }
  }

  .root:is([data-disabled], :disabled) + .indicator {
    opacity: var(--select-disabled-opacity, var(--opacity-disabled));
  }

  .root:not(:disabled, [data-disabled]):hover + .indicator {
    @media (hover: hover) {
      background-color: var(--select-action-bg-hover, var(--color-muted));
      color: var(--select-action-color-hover, var(--color-foreground));
    }
  }

  .root:is([multiple], [size]:not([size='1'])) + .indicator {
    display: none;
  }
}
